"""
T2 RBAC System — Auth Routes (Sample 1)

Variant strategy:
- Centralized try/except wrapping the entire request handler
- Manual JSON response construction via json.dumps + Response (no jsonify)
- Early-return field validation before entering the try block

Register as a Flask Blueprint named 'auth_bp'.
"""

import json
import datetime

import jwt as pyjwt
from flask import Blueprint, request, Response, current_app

from models import User
from middleware import hash_password

auth_bp = Blueprint('auth_bp', __name__)


@auth_bp.route('/login', methods=['POST'])
def login():
    """Authenticate user and return a JWT token.

    Request body: {"username": str, "password": str}
    Success response (200): {"status": "ok", "data": {"token": str}}
    Error responses: 400 (missing fields), 401 (bad credentials)
    """
    body = request.get_json(silent=True) or {}

    # --- Early-return validation (expected input errors, not exceptions) ---
    if not body.get('username'):
        return Response(
            json.dumps({'status': 'error', 'message': 'Missing username'}),
            status=400,
            content_type='application/json',
        )
    if not body.get('password'):
        return Response(
            json.dumps({'status': 'error', 'message': 'Missing password'}),
            status=400,
            content_type='application/json',
        )

    # --- Core logic wrapped in a single try/except ---
    try:
        user = User.query.filter_by(username=body['username']).first()

        # User must exist AND password must match
        if user is None or user.password_hash != hash_password(body['password']):
            return Response(
                json.dumps({'status': 'error', 'message': 'Invalid credentials'}),
                status=401,
                content_type='application/json',
            )

        # Build JWT payload
        secret = current_app.config['JWT_SECRET']
        expiry_hours = current_app.config['JWT_EXPIRY_HOURS']
        now = datetime.datetime.utcnow()
        payload = {
            'user_id': user.id,
            'tenant_id': user.tenant_id,
            'exp': now + datetime.timedelta(hours=expiry_hours),
        }
        token = pyjwt.encode(payload, secret, algorithm='HS256')

        return Response(
            json.dumps({'status': 'ok', 'data': {'token': token}}),
            status=200,
            content_type='application/json',
        )

    except Exception:
        # Centralized error handler: any unexpected failure returns 500
        return Response(
            json.dumps({'status': 'error', 'message': 'Internal server error'}),
            status=500,
            content_type='application/json',
        )

